const root = $input.first().json;
const feed = root.feed || root.data?.feed || root.rss || root.data?.rss || {};
const items = feed.entry || feed.channel?.item || [];
const arr = Array.isArray(items) ? items : (items ? [items] : []);
const today = new Date().toISOString().split('T')[0];

return arr.filter(e => e).map(entry => ({
  json: {
    'Date': today,
    'Company Domain': '',
    'Company Name': '',
    'Signal Type': '1',
    'Signal Summary': String(entry.title || entry.title?.[0] || '')
      .replace(/<[^>]+>/g, '')
      .trim(),
    'Source URL': String(
      entry.link?.href ||
      entry.link?.[0]?.$?.href ||
      entry.link?.[0] ||
      entry.link ||
      ''
    ).trim(),
    'Status': 'New'
  }
}));

