const feed = $input.first().json.data;
const items = feed?.rss?.channel?.item || feed?.feed?.entry || [];
const arr = Array.isArray(items) ? items : [items];
const today = new Date().toISOString().split('T')[0];

return arr.filter(e => e).map(entry => ({
  json: {
    'Date': today,
    'Company Domain': '',
