const items = $input.all().filter(item => {
  const j = item.json || {};
  return j['Signal Summary'] && j['Source URL'];
});

if (items.length === 0) {
  return [{
    json: {
      model: 'moonshotai/kimi-k2-0905',
      response_format: { type: 'json_object' },
      messages: [
        {
          role: 'system',
          content: 'You are a B2B SaaS company domain extractor. Return ONLY a valid JSON object in this exact format: {"domains": []}.'
        },
        {
          role: 'user',
          content: 'Extract the primary company domain for each signal below. Return exactly 0 entries in the domains array.'
        }
      ],
      temperature: 0,
      max_tokens: 800,
      originalItems: []
    }
  }];
}

const originalItems = items.map(i => i.json);

const signalList = originalItems.map((item, i) => {
  const title = String(item['Signal Summary'] || '')
    .replace(/"/g, "'")
    .slice(0, 200);
  const url = String(item['Source URL'] || '')
    .slice(0, 150);
  return `${i}: "${title}" | ${url}`;
}).join('\n');

return [{
  json: {
    model: 'moonshotai/kimi-k2-0905',
    response_format: { type: 'json_object' },
    messages: [
      {
        role: 'system',
        content: 'You are a B2B SaaS company domain extractor. You receive a numbered list of signal headlines sourced from Google Alerts, Reddit, and HN. Each headline is about or mentions a B2B SaaS company. Your job is to identify the PRIMARY company being discussed in each signal and return its exact web domain (e.g. gong.io, hubspot.com, gainsight.com, churnzero.com). Return ONLY a valid JSON object in this exact format: {"domains": ["domain1.com", "domain2.com", "..."]} with exactly one entry per input signal in the same order. Use an empty string "" if you cannot identify the company. Do not include any explanation, markdown, or text outside the JSON object.'
      },
      {
        role: 'user',
        content: `Extract the primary company domain for each signal below. Return exactly ${originalItems.length} entries in the domains array.\n\n${signalList}`
      }
    ],
    temperature: 0,
    max_tokens: 800,
    originalItems
  }
}];

// ─────────────────────────────────────────────────────────────────────────
// WHY WE RECOVER originalItems BY NODE NAME
// ─────────────────────────────────────────────────────────────────────────
// n8n HTTP Request nodes replace $json entirely with the API response body.
// The originalItems array we built in 'Code — Prepare Domain Extraction Batch'
// is NOT in $json here — it was consumed by the HTTP node's expression.
// We recover it by referencing the upstream node by name, exactly as WF4
// does when it recovers the merged account row after the OpenRouter scoring call.
// ─────────────────────────────────────────────────────────────────────────

const response      = $input.first().json;
const batchNode     = $('Code — Prepare Domain Extraction Batch').first().json;
const originalItems = batchNode.originalItems || [];

// ── Parse LLM response ───────────────────────────────────────────────────
let domains = [];
try {
  const content = response?.choices?.[0]?.message?.content || '{"domains":[]}';
  const cleaned = typeof content === 'string' ? content.replace(/```json\n?|\n?```/g, '').trim() : '';
  const parsed = JSON.parse(cleaned || '{"domains":[]}}');
  domains = Array.isArray(parsed.domains) ? parsed.domains : [];
} catch (e) {
  // LLM returned unparseable content — proceed with empty domains.
  // Items with no domain will be dropped below, which is correct:
  // a signal with unknown domain contributes nothing to WF3's clustering.
  domains = [];
}

// ── Re-expand: one output item per original signal ───────────────────────
const results = [];
for (let i = 0; i < originalItems.length; i++) {
  const item   = originalItems[i];

  // Prefer any domain already set on the item (e.g. WF2-style extraction)
  // then fall back to what the LLM returned
  const extracted   = (domains[i] || '').toString().toLowerCase()
                        .replace(/^https?:\/\//, '')
                        .replace(/^www\./, '')
                        .replace(/\/.*$/, '')
                        .trim();
  const finalDomain = (item['Company Domain'] || extracted || '').trim();

  // Drop signals where we still have no domain — they add noise without value
  if (!finalDomain) continue;

  // Best-effort company name: capitalise the domain root if name is missing
  const domainRoot     = finalDomain.split('.')[0];
  const inferredName   = domainRoot.charAt(0).toUpperCase() + domainRoot.slice(1);
  const finalName      = (item['Company Name'] || inferredName).trim();

  results.push({
    json: {
      ...item,
      'Company Domain': finalDomain,
      'Company Name':   finalName
    }
  });
}

// Return empty array if LLM could not identify any domain.
// Empty array in n8n means 'no items' — downstream Sheets node skips gracefully.
return results;
